import { Router, Request, Response } from 'express';
import { Product } from '../models/Product';
import { authMiddleware } from '../middleware/auth';
import { validateBody } from '../middleware/validate';
import { db } from '../utils/db';
import { logger } from '../utils/logger';

const router = Router();

router.get('/', async (req: Request, res: Response) => {
  try {
    const products = await db.query('SELECT * FROM products WHERE active = true');
    res.json({ data: products.rows });
  } catch (err) {
    logger.error('Failed to fetch products', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

router.get('/:id', async (req: Request, res: Response) => {
  try {
    const { id } = req.params;
    const product = await db.query('SELECT * FROM products WHERE id = $1', [id]);
    if (!product.rows[0]) return res.status(404).json({ error: 'Product not found' });
    res.json({ data: product.rows[0] });
  } catch (err) {
    logger.error('Failed to fetch product', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

router.post('/', authMiddleware, validateBody('createProduct'), async (req: Request, res: Response) => {
  try {
    const { name, sku, price, quantity } = req.body;
    const result = await db.query(
      'INSERT INTO products (name, sku, price, quantity) VALUES ($1, $2, $3, $4) RETURNING *',
      [name, sku, price, quantity]
    );
    res.status(201).json({ data: result.rows[0] });
  } catch (err) {
    logger.error('Failed to create product', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

router.put('/:id', authMiddleware, validateBody('updateProduct'), async (req: Request, res: Response) => {
  try {
    const { id } = req.params;
    const { name, price, quantity } = req.body;
    const result = await db.query(
      'UPDATE products SET name = $1, price = $2, quantity = $3, updated_at = NOW() WHERE id = $4 RETURNING *',
      [name, price, quantity, id]
    );
    if (!result.rows[0]) return res.status(404).json({ error: 'Product not found' });
    res.json({ data: result.rows[0] });
  } catch (err) {
    logger.error('Failed to update product', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

router.delete('/:id', authMiddleware, async (req: Request, res: Response) => {
  try {
    const { id } = req.params;
    await db.query('UPDATE products SET active = false WHERE id = $1', [id]);
    res.status(204).send();
  } catch (err) {
    logger.error('Failed to delete product', err);
    res.status(500).json({ error: 'Internal server error' });
  }
});

export default router;

