Same pattern confirmed — inline handlers with duplicated error handling. I also notice the orders route uses `(req as any).user.id` which we should type properly. Here's my plan:

1. Create a `BaseController` class with shared error handling
2. Create individual controller classes per resource
3. Update route files to use controllers

Let me create the base controller first since every handler uses the same error structure.

```tool_call
{"name": "write_file", "arguments": {"path": "~/projects/inventory-api/src/controllers/BaseController.ts", "content": "import { Request, Response, NextFunction } from 'express';
import { logger } from '../utils/logger';

export interface AuthenticatedRequest extends Request {
  user: { id: string; email: string; role: string; };
}

export abstract class BaseController {
  protected handleRequest(handler: (req: Request, res: Response) => Promise<void>) {
    return async (req: Request, res: Response, next: NextFunction) => {
      try {
        await handler(req, res);
      } catch (err) {
        logger.error(`${this.constructor.name} error`, err);
        res.status(500).json({ error: 'Internal server error' });
      }
    };
  }

  protected notFound(res: Response, resource: string): Response {
    return res.status(404).json({ error: `${resource} not found` });
  }
}
"}}
```

