from flask import Flask, request, jsonify, g
from functools import wraps
import sqlite3
import jwt
import hashlib
import os
from datetime import datetime, timedelta

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'dev-key')
app.config['DATABASE'] = 'fleet.db'

def get_db():
    if 'db' not in g:
        g.db = sqlite3.connect(app.config['DATABASE'])
        g.db.row_factory = sqlite3.Row
    return g.db

@app.teardown_appcontext
def close_db(exception):
    db = g.pop('db', None)
    if db is not None:
        db.close()

def require_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization', '').replace('Bearer ', '')
        if not token:
            return jsonify({'error': 'Token required'}), 401
        try:
            payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
            g.user_id = payload['user_id']
            g.user_role = payload['role']
        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token expired'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'error': 'Invalid token'}), 401
        return f(*args, **kwargs)
    return decorated

@app.route('/api/auth/login', methods=['POST'])
def login():
    data = request.get_json()
    db = get_db()
    user = db.execute('SELECT * FROM users WHERE email = ?', (data['email'],)).fetchone()
    if not user:
        return jsonify({'error': 'Invalid credentials'}), 401
    password_hash = hashlib.sha256((data['password'] + user['salt']).encode()).hexdigest()
    if password_hash != user['password_hash']:
        return jsonify({'error': 'Invalid credentials'}), 401
    token = jwt.encode({'user_id': user['id'], 'role': user['role'], 'exp': datetime.utcnow() + timedelta(hours=24)}, app.config['SECRET_KEY'])
    return jsonify({'token': token})

@app.route('/api/vehicles', methods=['GET'])
@require_auth
def get_vehicles():
    db = get_db()
    vehicles = db.execute('SELECT * FROM vehicles WHERE active = 1').fetchall()
    return jsonify({'data': [dict(v) for v in vehicles]})

@app.route('/api/vehicles', methods=['POST'])
@require_auth
def create_vehicle():
    data = request.get_json()
    db = get_db()
    db.execute('INSERT INTO vehicles (vin, make, model, year, plate, active) VALUES (?, ?, ?, ?, ?, 1)', (data['vin'], data['make'], data['model'], data['year'], data['plate']))
    db.commit()
    return jsonify({'message': 'Vehicle created'}), 201

@app.route('/api/vehicles/<int:vid>/location', methods=['POST'])
@require_auth
def update_location(vid):
    data = request.get_json()
    db = get_db()
    db.execute('INSERT INTO locations (vehicle_id, lat, lng, speed, heading, timestamp) VALUES (?, ?, ?, ?, ?, ?)', (vid, data['lat'], data['lng'], data.get('speed', 0), data.get('heading', 0), datetime.utcnow().isoformat()))
    db.commit()
    return jsonify({'message': 'Location updated'})

@app.route('/api/drivers', methods=['GET'])
@require_auth
def get_drivers():
    db = get_db()
    drivers = db.execute('SELECT id, name, license_number, phone, status FROM drivers WHERE active = 1').fetchall()
    return jsonify({'data': [dict(d) for d in drivers]})

@app.route('/api/trips', methods=['POST'])
@require_auth
def create_trip():
    data = request.get_json()
    db = get_db()
    db.execute('INSERT INTO trips (vehicle_id, driver_id, start_time, origin, destination, status) VALUES (?, ?, ?, ?, ?, ?)', (data['vehicle_id'], data['driver_id'], datetime.utcnow().isoformat(), data['origin'], data['destination'], 'in_progress'))
    db.execute('UPDATE drivers SET status = ? WHERE id = ?', ('on_trip', data['driver_id']))
    db.commit()
    return jsonify({'message': 'Trip started'}), 201

