package main

import (
	"database/sql"
	"fmt"
	_ "github.com/lib/pq"
)

var db *sql.DB

func InitDB(connStr string) error {
	var err error
	db, err = sql.Open("postgres", connStr)
	if err != nil {
		return fmt.Errorf("failed to open database: %w", err)
	}
	return db.Ping()
}

func GetTasks(boardID int) ([]Task, error) {
	rows, err := db.Query("SELECT id, title, description, status, priority, assignee_id, board_id, created_at, updated_at FROM tasks WHERE board_id = $1 ORDER BY priority DESC", boardID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var tasks []Task
	for rows.Next() {
		var t Task
		err := rows.Scan(&t.ID, &t.Title, &t.Description, &t.Status, &t.Priority, &t.AssigneeID, &t.BoardID, &t.CreatedAt, &t.UpdatedAt)
		if err != nil {
			return nil, err
		}
		tasks = append(tasks, t)
	}
	return tasks, nil
}

func CreateTask(req CreateTaskRequest) (*Task, error) {
	var t Task
	err := db.QueryRow("INSERT INTO tasks (title, description, status, priority, assignee_id, board_id) VALUES ($1, $2, 'todo', $3, $4, $5) RETURNING id, title, description, status, priority, assignee_id, board_id, created_at, updated_at", req.Title, req.Description, req.Priority, req.AssigneeID, req.BoardID).Scan(&t.ID, &t.Title, &t.Description, &t.Status, &t.Priority, &t.AssigneeID, &t.BoardID, &t.CreatedAt, &t.UpdatedAt)
	if err != nil {
		return nil, err
	}
	return &t, nil
}

func GetUserByEmail(email string) (*User, error) {
	var u User
	err := db.QueryRow("SELECT id, email, password_hash, name FROM users WHERE email = $1", email).Scan(&u.ID, &u.Email, &u.PasswordHash, &u.Name)
	if err != nil {
		return nil, err
	}
	return &u, nil
}

