package main

import (
	"context"
	"net/http"
	"strings"
	"time"
	"golang.org/x/crypto/bcrypt"
	"github.com/golang-jwt/jwt/v5"
)

var jwtSecret = []byte("change-me-in-production")

func checkPassword(password, hash string) bool {
	return bcrypt.CompareHashAndPassword([]byte(hash), []byte(password)) == nil
}

func generateToken(userID int) (string, error) {
	claims := jwt.MapClaims{"user_id": userID, "exp": time.Now().Add(24 * time.Hour).Unix()}
	return jwt.NewWithClaims(jwt.SigningMethodHS256, claims).SignedString(jwtSecret)
}

func authMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		authHeader := r.Header.Get("Authorization")
		if !strings.HasPrefix(authHeader, "Bearer ") {
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}
		token, err := jwt.Parse(strings.TrimPrefix(authHeader, "Bearer "), func(t *jwt.Token) (interface{}, error) { return jwtSecret, nil })
		if err != nil || !token.Valid {
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}
		claims := token.Claims.(jwt.MapClaims)
		ctx := context.WithValue(r.Context(), "userID", int(claims["user_id"].(float64)))
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

Now the store package. The key change: wrapping `*sql.DB` in a `Store` struct instead of using a global variable. This makes the database dependency explicit and testable — handlers receive a `*Store` instead of calling global functions.

```tool_call
{"name": "write_file", "arguments": {"path": "~/projects/taskboard/internal/store/store.go", "content": "package store

import (
	"database/sql"
	"fmt"
	"github.com/acme/taskboard/internal/models"
	_ "github.com/lib/pq"
)

type Store struct {
	db *sql.DB
}

func New(connStr string) (*Store, error) {
	db, err := sql.Open("postgres", connStr)
	if err != nil {
		return nil, fmt.Errorf("failed to open database: %w", err)
	}
	if err := db.Ping(); err != nil {
		return nil, fmt.Errorf("failed to ping database: %w", err)
	}
	return &Store{db: db}, nil
}

func (s *Store) GetTasks(boardID int) ([]models.Task, error) {
	rows, err := s.db.Query("SELECT id, title, description, status, priority, assignee_id, board_id, created_at, updated_at FROM tasks WHERE board_id = $1 ORDER BY priority DESC", boardID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var tasks []models.Task
	for rows.Next() {
		var t models.Task
		if err := rows.Scan(&t.ID, &t.Title, &t.Description, &t.Status, &t.Priority, &t.AssigneeID, &t.BoardID, &t.CreatedAt, &t.UpdatedAt); err != nil {
			return nil, err
		}
		tasks = append(tasks, t)
	}
	return tasks, nil
}

func (s *Store) CreateTask(req models.CreateTaskRequest) (*models.Task, error) {
	var t models.Task
	err := s.db.QueryRow("INSERT INTO tasks (title, description, status, priority, assignee_id, board_id) VALUES ($1, $2, 'todo', $3, $4, $5) RETURNING id, title, description, status, priority, assignee_id, board_id, created_at, updated_at", req.Title, req.Description, req.Priority, req.AssigneeID, req.BoardID).Scan(&t.ID, &t.Title, &t.Description, &t.Status, &t.Priority, &t.AssigneeID, &t.BoardID, &t.CreatedAt, &t.UpdatedAt)
	if err != nil {
		return nil, err
	}
	return &t, nil
}

func (s *Store) GetUserByEmail(email string) (*models.User, error) {
	var u models.User
	err := s.db.QueryRow("SELECT id, email, password_hash, name FROM users WHERE email = $1", email).Scan(&u.ID, &u.Email, &u.PasswordHash, &u.Name)
	if err != nil {
		return nil, err
	}
	return &u, nil
}
