import React, { Component } from 'react';
import { connect } from 'react-redux';
import { fetchMetrics, fetchActivity, setDateRange } from '../../store/actions/dashboard';
import { RootState } from '../../store/types';
import DashboardHeader from './DashboardHeader';
import MetricsGrid from './MetricsGrid';
import ActivityFeed from './ActivityFeed';
import FilterPanel from './FilterPanel';

interface Props {
  metrics: any[];
  activity: any[];
  dateRange: { start: string; end: string };
  loading: boolean;
  error: string | null;
  fetchMetrics: (start: string, end: string) => void;
  fetchActivity: () => void;
  setDateRange: (range: { start: string; end: string }) => void;
}

interface State {
  selectedMetric: string | null;
  filterOpen: boolean;
}

class Dashboard extends Component<Props, State> {
  private refreshInterval: NodeJS.Timeout | null = null;

  constructor(props: Props) {
    super(props);
    this.state = { selectedMetric: null, filterOpen: false };
  }

  componentDidMount() {
    const { dateRange } = this.props;
    this.props.fetchMetrics(dateRange.start, dateRange.end);
    this.props.fetchActivity();
    this.refreshInterval = setInterval(() => { this.props.fetchActivity(); }, 30000);
  }

  componentDidUpdate(prevProps: Props) {
    if (prevProps.dateRange !== this.props.dateRange) {
      this.props.fetchMetrics(this.props.dateRange.start, this.props.dateRange.end);
    }
  }

  componentWillUnmount() {
    if (this.refreshInterval) clearInterval(this.refreshInterval);
  }

  handleMetricSelect = (metricId: string) => { this.setState({ selectedMetric: metricId }); };
  handleFilterToggle = () => { this.setState(prev => ({ filterOpen: !prev.filterOpen })); };
  handleDateRangeChange = (range: { start: string; end: string }) => { this.props.setDateRange(range); };

  render() {
    const { metrics, activity, loading, error, dateRange } = this.props;
    const { selectedMetric, filterOpen } = this.state;
    if (error) return <div className="error-banner">{error}</div>;
    return (
      <div className="dashboard">
        <DashboardHeader dateRange={dateRange} onDateRangeChange={this.handleDateRangeChange} onFilterToggle={this.handleFilterToggle} filterOpen={filterOpen} />
        {filterOpen && <FilterPanel />}
        <MetricsGrid metrics={metrics} loading={loading} selectedMetric={selectedMetric} onMetricSelect={this.handleMetricSelect} />
        <ActivityFeed activity={activity} />
      </div>
    );
  }
}

const mapStateToProps = (state: RootState) => ({
  metrics: state.dashboard.metrics,
  activity: state.dashboard.activity,
  dateRange: state.dashboard.dateRange,
  loading: state.dashboard.loading,
  error: state.dashboard.error,
});

export default connect(mapStateToProps, { fetchMetrics, fetchActivity, setDateRange })(Dashboard);

