  constructor(props: Props) {
    super(props);
    this.state = { editingDate: false, tempStart: props.dateRange.start, tempEnd: props.dateRange.end };
  }

  componentDidUpdate(prevProps: Props) {
    if (prevProps.dateRange !== this.props.dateRange) {
      this.setState({ tempStart: this.props.dateRange.start, tempEnd: this.props.dateRange.end });
    }
  }

  handleApply = () => {
    this.props.onDateRangeChange({ start: this.state.tempStart, end: this.state.tempEnd });
    this.setState({ editingDate: false });
  };

  render() {
    const { onFilterToggle, filterOpen } = this.props;
    const { editingDate, tempStart, tempEnd } = this.state;
    return (
