              <input type="date" value={tempEnd} onChange={e => this.setState({ tempEnd: e.target.value })} />
              <button onClick={this.handleApply}>Apply</button>
              <button onClick={() => this.setState({ editingDate: false })}>Cancel</button>
            </div>
