    );
  }
}

export default DashboardHeader;

Now I have a clear picture. Here are the lifecycle-to-hooks mappings:

- `connect()` → `useSelector` + `useDispatch`
- `componentDidMount` → `useEffect(..., [])`
- `componentDidUpdate(prevProps)` watching dateRange → `useEffect(..., [dateRange])`
- `componentWillUnmount` cleanup → return function in `useEffect`
- Class state → `useState`
- Instance methods → `useCallback`

