from .models import Author, Book, Review

@require_http_methods(['GET'])
def list_books(request):
    books = Book.objects.select_related('author').all()
    data = [{'id': b.id, 'title': b.title, 'isbn': b.isbn, 'author': {'id': b.author.id, 'name': b.author.name}, 'price': str(b.price), 'stock': b.stock} for b in books]
    return JsonResponse({'data': data})

@require_http_methods(['GET'])
def book_detail(request, pk):
    try:
        b = Book.objects.select_related('author').get(pk=pk)
    except Book.DoesNotExist:
        return JsonResponse({'error': 'Not found'}, status=404)
    reviews = Review.objects.filter(book=b).select_related('user')
    data = {'id': b.id, 'title': b.title, 'isbn': b.isbn, 'author': {'id': b.author.id, 'name': b.author.name, 'bio': b.author.bio}, 'price': str(b.price), 'stock': b.stock, 'description': b.description, 'reviews': [{'id': r.id, 'user': r.user.username, 'rating': r.rating, 'comment': r.comment} for r in reviews]}
    return JsonResponse({'data': data})

@csrf_exempt
@login_required
@require_http_methods(['POST'])
def create_book(request):
    try:
        body = json.loads(request.body)
    except json.JSONDecodeError:
        return JsonResponse({'error': 'Invalid JSON'}, status=400)
    try:
        author = Author.objects.get(pk=body['author_id'])
    except Author.DoesNotExist:
        return JsonResponse({'error': 'Author not found'}, status=400)
    book = Book.objects.create(title=body['title'], isbn=body['isbn'], author=author, published_date=body['published_date'], price=body['price'], stock=body.get('stock', 0), description=body.get('description', ''))
    return JsonResponse({'data': {'id': book.id, 'title': book.title}}, status=201)

@csrf_exempt
@login_required
@require_http_methods(['POST'])
def create_review(request, book_pk):
    try:
        body = json.loads(request.body)
    except json.JSONDecodeError:
        return JsonResponse({'error': 'Invalid JSON'}, status=400)
    try:
        book = Book.objects.get(pk=book_pk)
    except Book.DoesNotExist:
        return JsonResponse({'error': 'Book not found'}, status=404)
    if Review.objects.filter(book=book, user=request.user).exists():
        return JsonResponse({'error': 'Already reviewed'}, status=400)
    review = Review.objects.create(book=book, user=request.user, rating=body['rating'], comment=body['comment'])
    return JsonResponse({'data': {'id': review.id, 'rating': review.rating}}, status=201)

