```tool_call
{"name": "write_file", "arguments": {"path": "~/projects/bookstore-api/books/viewsets.py", "content": "from rest_framework import viewsets, permissions, status
from rest_framework.response import Response
from .models import Author, Book, Review
from .serializers import AuthorSerializer, BookListSerializer, BookDetailSerializer, ReviewSerializer


class AuthorViewSet(viewsets.ReadOnlyModelViewSet):
    queryset = Author.objects.all()
    serializer_class = AuthorSerializer


class BookViewSet(viewsets.ModelViewSet):
    queryset = Book.objects.select_related('author').all()

    def get_serializer_class(self):
        if self.action == 'retrieve':
            return BookDetailSerializer
        return BookListSerializer

    def get_permissions(self):
        if self.action in ('create', 'update', 'partial_update', 'destroy'):
            return [permissions.IsAuthenticated()]
        return [permissions.AllowAny()]

    def get_queryset(self):
        qs = super().get_queryset()
        if self.action == 'retrieve':
