use std::fs::File;
use std::io::{BufRead, BufReader};
use std::path::PathBuf;
use clap::Parser;
use chrono::NaiveDateTime;
use serde::Serialize;
use regex::Regex;

#[derive(Parser)]
#[command(name = "logparse", about = "Parse and analyze log files")]
struct Cli {
    #[arg(help = "Path to log file")]
    file: PathBuf,
    #[arg(short, long, default_value = "text")]
    format: String,
    #[arg(short, long)]
    level: Option<String>,
    #[arg(long)]
    after: Option<String>,
    #[arg(long)]
    before: Option<String>,
    #[arg(short, long)]
    stats: bool,
}

#[derive(Debug, Clone, Serialize)]
struct LogEntry {
    timestamp: String,
    level: String,
    source: String,
    message: String,
    line_number: usize,
}

#[derive(Debug, Serialize)]
struct LogStats {
    total: usize,
    errors: usize,
    warnings: usize,
    info: usize,
    debug: usize,
    earliest: Option<String>,
    latest: Option<String>,
}

fn parse_line(line: &str, line_number: usize) -> Option<LogEntry> {
    let re = Regex::new(r"^\[(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})\] \[(ERROR|WARN|INFO|DEBUG)\] \[([^\]]+)\] (.+)$").unwrap();
    let caps = re.captures(line)?;
    Some(LogEntry { timestamp: caps[1].to_string(), level: caps[2].to_string(), source: caps[3].to_string(), message: caps[4].to_string(), line_number })
}

fn read_log_file(path: &PathBuf) -> Result<Vec<LogEntry>, Box<dyn std::error::Error>> {
    let file = File::open(path)?;
    let reader = BufReader::new(file);
    let mut entries = Vec::new();
    for (i, line) in reader.lines().enumerate() {
        if let Some(entry) = parse_line(&line?, i + 1) {
            entries.push(entry);
        }
    }
    Ok(entries)
}

fn filter_entries(entries: Vec<LogEntry>, level: &Option<String>, after: &Option<String>, before: &Option<String>) -> Vec<LogEntry> {
    entries.into_iter().filter(|e| {
        if let Some(ref lvl) = level {
            if e.level != lvl.to_uppercase() { return false; }
        }
        if let Some(ref a) = after {
            if let (Ok(et), Ok(at)) = (NaiveDateTime::parse_from_str(&e.timestamp, "%Y-%m-%d %H:%M:%S"), NaiveDateTime::parse_from_str(a, "%Y-%m-%d %H:%M:%S")) {
                if et < at { return false; }
            }
        }
        if let Some(ref b) = before {
            if let (Ok(et), Ok(bt)) = (NaiveDateTime::parse_from_str(&e.timestamp, "%Y-%m-%d %H:%M:%S"), NaiveDateTime::parse_from_str(b, "%Y-%m-%d %H:%M:%S")) {
                if et > bt { return false; }
            }
        }
        true
    }).collect()
}

fn compute_stats(entries: &[LogEntry]) -> LogStats {
    LogStats {
        total: entries.len(),
        errors: entries.iter().filter(|e| e.level == "ERROR").count(),
        warnings: entries.iter().filter(|e| e.level == "WARN").count(),
        info: entries.iter().filter(|e| e.level == "INFO").count(),
        debug: entries.iter().filter(|e| e.level == "DEBUG").count(),
        earliest: entries.first().map(|e| e.timestamp.clone()),
        latest: entries.last().map(|e| e.timestamp.clone()),
    }
}

fn format_text(entries: &[LogEntry]) {
    for e in entries { println!("{} [{}] [{}] {}", e.timestamp, e.level, e.source, e.message); }
}

fn format_json(entries: &[LogEntry]) {
    println!("{}", serde_json::to_string_pretty(entries).unwrap());
}

fn format_csv(entries: &[LogEntry]) {
    println!("timestamp,level,source,message,line");
    for e in entries { println!("{},{},{},\"{}\",{}", e.timestamp, e.level, e.source, e.message.replace('"', "\"\""), e.line_number); }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let cli = Cli::parse();
    let entries = read_log_file(&cli.file)?;
    let filtered = filter_entries(entries, &cli.level, &cli.after, &cli.before);
    if cli.stats {
        let stats = compute_stats(&filtered);
        println!("{}", serde_json::to_string_pretty(&stats).unwrap());
        return Ok(());
    }
    match cli.format.as_str() {
        "json" => format_json(&filtered),
        "csv" => format_csv(&filtered),
        _ => format_text(&filtered),
    }
    Ok(())
}

