import React, { createContext, useContext, useEffect, useRef, useState } from 'react';

interface WSContextType {
  lastMessage: any;
  isConnected: boolean;
  subscribe: (channel: string, callback: (data: any) => void) => void;
  unsubscribe: (channel: string) => void;
}

const WSContext = createContext<WSContextType | null>(null);

export function WebSocketProvider({ children }: { children: React.ReactNode }) {
  const wsRef = useRef<WebSocket | null>(null);
  const [isConnected, setIsConnected] = useState(false);
  const [lastMessage, setLastMessage] = useState<any>(null);
  const subscribers = useRef<Map<string, Set<(data: any) => void>>>(new Map());

  useEffect(() => {
    const ws = new WebSocket(process.env.REACT_APP_WS_URL || 'ws://localhost:8080');
    wsRef.current = ws;

    ws.onopen = () => setIsConnected(true);
    ws.onclose = () => {
      setIsConnected(false);
      setTimeout(() => {
        wsRef.current = new WebSocket(process.env.REACT_APP_WS_URL || 'ws://localhost:8080');
      }, 3000);
    };

    ws.onmessage = (event) => {
      const data = JSON.parse(event.data);
      setLastMessage(data);
      const channelSubs = subscribers.current.get(data.channel);
      if (channelSubs) {
        channelSubs.forEach(cb => cb(data.payload));
      }
    };

    return () => ws.close();
  }, []);

  const subscribe = (channel: string, callback: (data: any) => void) => {
    if (!subscribers.current.has(channel)) {
      subscribers.current.set(channel, new Set());
    }
    subscribers.current.get(channel)!.add(callback);
  };

  const unsubscribe = (channel: string) => {
    subscribers.current.delete(channel);
  };

  return (
    <WSContext.Provider value={{ lastMessage, isConnected, subscribe, unsubscribe }}>
      {children}
    </WSContext.Provider>
  );
}

export const useWSContext = () => {
  const ctx = useContext(WSContext);
  if (!ctx) throw new Error('useWSContext must be used within WebSocketProvider');
  return ctx;
};

