package planner

import (
	"sort"
	"time"
)

type Slot struct {
	ID        int       `json:"id"`
	StartTime time.Time `json:"start_time"`
	EndTime   time.Time `json:"end_time"`
	Capacity  int       `json:"capacity"`
	Booked    int       `json:"booked"`
}

func Optimize(slots []Slot) []Slot {
	// Filter to only available slots (not fully booked)
	available := make([]Slot, 0)
	for _, s := range slots {
		if s.Booked < s.Capacity {
			available = append(available, s)
		}
	}

	// Sort by start time
	sort.Slice(available, func(i, j int) bool {
		return available[i].StartTime.Before(available[j].StartTime)
	})

	// Remove overlapping slots, prefer earlier ones
	result := make([]Slot, 0)
	for _, s := range available {
		if len(result) == 0 || s.StartTime.After(result[len(result)-1].EndTime) {
			result = append(result, s)
		}
	}

	return result
}

