func GetSlots(date string) ([]planner.Slot, error) {
	rows, err := db.Query("SELECT id, start_time, end_time, capacity, booked FROM slots WHERE date = $1", date)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var slots []planner.Slot
	for rows.Next() {
		var s planner.Slot
		if err := rows.Scan(&s.ID, &s.StartTime, &s.EndTime, &s.Capacity, &s.Booked); err != nil {
			return nil, err
		}
