import sharp from 'sharp';
import path from 'path';
import fs from 'fs/promises';

interface ProcessOptions {
  width?: number;
  height?: number;
  quality?: number;
  watermark?: boolean;
  format?: 'jpeg' | 'png' | 'webp';
}

export async function processImage(inputPath: string, outputDir: string, options: ProcessOptions): Promise<string[]> {
  const results: string[] = [];
  const imageBuffer = await fs.readFile(inputPath);
  const metadata = await sharp(imageBuffer).metadata();

  // Generate multiple sizes
  const sizes = [
    { name: 'thumb', width: 150, height: 150 },
    { name: 'small', width: 480 },
    { name: 'medium', width: 1024 },
    { name: 'large', width: 2048 },
    { name: 'original', width: metadata.width },
  ];

  for (const size of sizes) {
    let pipeline = sharp(imageBuffer)
      .resize(size.width, size.height, { fit: 'inside', withoutEnlargement: true });

    if (options.watermark) {
      const watermarkBuffer = await fs.readFile(path.join(__dirname, '../../assets/watermark.png'));
      pipeline = pipeline.composite([{ input: watermarkBuffer, gravity: 'southeast' }]);
    }

    const outputFormat = options.format || 'jpeg';
    const outputPath = path.join(outputDir, `${size.name}.${outputFormat}`);

    if (outputFormat === 'jpeg') {
      await pipeline.jpeg({ quality: options.quality || 85 }).toFile(outputPath);
    } else if (outputFormat === 'webp') {
      await pipeline.webp({ quality: options.quality || 85 }).toFile(outputPath);
    } else {
      await pipeline.png().toFile(outputPath);
    }

    results.push(outputPath);
  }

  return results;
}

