from jsonschema import validate, ValidationError, SchemaError

def load_json(path: str) -> dict:
    with open(path, 'r') as f:
        return json.load(f)

def validate_config(config_path: str, schema: dict) -> dict:
    """Validate a single config file. Returns a result dict."""
    result = {'file': config_path, 'valid': False, 'errors': []}
    try:
        config = load_json(config_path)
    except json.JSONDecodeError as e:
        result['errors'].append({'type': 'parse_error', 'message': str(e)})
        return result
    except FileNotFoundError:
        result['errors'].append({'type': 'file_not_found', 'message': f'{config_path} not found'})
        return result

    try:
        validate(instance=config, schema=schema)
        result['valid'] = True
    except ValidationError as e:
        result['errors'].append({
            'type': 'validation_error',
            'message': e.message,
            'path': ' > '.join(str(p) for p in e.absolute_path),
        })

    return result

def main():
    parser = argparse.ArgumentParser(description='Validate JSON config files against a schema')
    parser.add_argument('schema', help='Path to the JSON schema file')
    parser.add_argument('configs', nargs='+', help='Paths to JSON config files to validate')
    parser.add_argument('--verbose', '-v', action='store_true', help='Pretty-print JSON output')
    args = parser.parse_args()

    try:
        schema = load_json(args.schema)
    except (json.JSONDecodeError, FileNotFoundError) as e:
        print(json.dumps({'error': f'Failed to load schema: {e}'}), file=sys.stderr)
        sys.exit(1)

    # Validate the schema itself first
    try:
        from jsonschema import Draft7Validator
        Draft7Validator.check_schema(schema)
    except SchemaError as e:
        print(json.dumps({'error': f'Invalid schema: {e.message}'}), file=sys.stderr)
        sys.exit(1)

    results = [validate_config(cfg, schema) for cfg in args.configs]
    all_valid = all(r['valid'] for r in results)

    output = {
        'total': len(results),
        'valid': sum(1 for r in results if r['valid']),
        'invalid': sum(1 for r in results if not r['valid']),
        'results': results,
    }

    indent = 2 if args.verbose else None
    print(json.dumps(output, indent=indent))
    sys.exit(0 if all_valid else 1)

if __name__ == '__main__':
    main()
