{"name": "write_file", "arguments": {"path": "~/projects/api-gateway/internal/middleware/ratelimit.go", "content": "package middleware

import (
	"context"
	"fmt"
	"net"
	"net/http"
	"time"

	redisClient "github.com/acme/api-gateway/internal/redis"
)

// Lua script for atomic sliding window rate limiting.
// Returns 1 if allowed, 0 if rate limited.
var rateLimitScript = `
local key = KEYS[1]
local limit = tonumber(ARGV[1])
local window = tonumber(ARGV[2])
local now = tonumber(ARGV[3])

-- Remove entries outside the window
redis.call('ZREMRANGEBYSCORE', key, 0, now - window)

local count = redis.call('ZCARD', key)
if count < limit then
  redis.call('ZADD', key, now, now .. '-' .. math.random(1000000))
  redis.call('EXPIRE', key, window)
  return 1
end
return 0
`

func extractIP(r *http.Request) string {
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		return xff
	}
	host, _, err := net.SplitHostPort(r.RemoteAddr)
	if err != nil {
		return r.RemoteAddr
	}
	return host
}

// RateLimit returns middleware that limits requests per IP using Redis.
// Works across multiple gateway instances behind a load balancer.
func RateLimit(requestsPerMinute int) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			ip := extractIP(r)
			key := fmt.Sprintf("ratelimit:%s", ip)

			ctx, cancel := context.WithTimeout(r.Context(), 100*time.Millisecond)
			defer cancel()

			result, err := redisClient.Client.Eval(ctx, rateLimitScript, []string{key},
				requestsPerMinute,
				60, // window in seconds
				time.Now().Unix(),
			).Int()

			if err != nil {
				// If Redis is down, allow the request (fail open)
				next.ServeHTTP(w, r)
				return
			}

			if result == 0 {
				w.Header().Set("Retry-After", "60")
				http.Error(w, "Rate limit exceeded", http.StatusTooManyRequests)
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}
"}}
