I'll update the logger to output structured JSON and add log rotation. I'll keep the same middleware signature and the response-time interception pattern we already built.

```tool_call
{"name": "write_file", "arguments": {"path": "~/projects/event-api/src/middleware/logger.ts", "content": "import { Request, Response, NextFunction } from 'express';
import fs from 'fs';
import path from 'path';

const LOG_DIR = path.join(process.cwd(), 'logs');
const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10MB
const MAX_FILES = 5;

if (!fs.existsSync(LOG_DIR)) {
  fs.mkdirSync(LOG_DIR, { recursive: true });
}

function getLogPath(index: number = 0): string {
  return index === 0
    ? path.join(LOG_DIR, 'access.log')
    : path.join(LOG_DIR, `access.${index}.log`);
}

function rotateIfNeeded(): void {
  const currentLog = getLogPath();
  try {
    const stats = fs.statSync(currentLog);
    if (stats.size < MAX_FILE_SIZE) return;
  } catch {
    return; // File doesn't exist yet
  }

  // Rotate: delete oldest, shift others
  const oldest = getLogPath(MAX_FILES - 1);
  if (fs.existsSync(oldest)) fs.unlinkSync(oldest);

  for (let i = MAX_FILES - 2; i >= 0; i--) {
    const from = getLogPath(i);
    const to = getLogPath(i + 1);
    if (fs.existsSync(from)) fs.renameSync(from, to);
  }
}

function writeLog(entry: Record<string, any>): void {
  const line = JSON.stringify(entry) + '\n';

  // Console output — pretty-printed summary
  const color = entry.status >= 400 ? '\x1b[31m' : entry.status >= 300 ? '\x1b[33m' : '\x1b[32m';
  console.log(`${color}${entry.method} ${entry.path} ${entry.status} ${entry.duration_ms}ms\x1b[0m`);

  // File output — structured JSON
  rotateIfNeeded();
  fs.appendFileSync(getLogPath(), line);
}

export function requestLogger(req: Request, res: Response, next: NextFunction) {
  const start = Date.now();

  const originalEnd = res.end;
  res.end = function (...args: any[]) {
    const duration = Date.now() - start;

    const entry: Record<string, any> = {
      timestamp: new Date().toISOString(),
      method: req.method,
      path: req.originalUrl,
      status: res.statusCode,
      duration_ms: duration,
      ip: req.ip,
      user_agent: req.headers['user-agent'],
    };

    // Include request body for mutating methods
    if (['POST', 'PUT', 'PATCH'].includes(req.method) && req.body) {
      // Redact sensitive fields
      const sanitized = { ...req.body };
      for (const key of ['password', 'token', 'secret', 'authorization', 'credit_card']) {
        if (key in sanitized) sanitized[key] = '[REDACTED]';
      }
      entry.body = sanitized;
    }

    writeLog(entry);
    return originalEnd.apply(res, args);
  } as any;

  next();
}
"}}
