func (s *BookmarkStore) Create(req models.CreateBookmarkRequest) (*models.Bookmark, error) {
	var b models.Bookmark
	err := s.db.QueryRow(
		"INSERT INTO bookmarks (url, title, description, tags) VALUES ($1, $2, $3, $4) RETURNING id, url, title, description, tags, created_at, updated_at",
		req.URL, req.Title, req.Description, pq.Array(req.Tags),
	).Scan(&b.ID, &b.URL, &b.Title, &b.Description, pq.Array(&b.Tags), &b.CreatedAt, &b.UpdatedAt)
	if err != nil {
		return nil, fmt.Errorf("create bookmark: %w", err)
	}
	return &b, nil
}

func (s *BookmarkStore) GetByID(id int) (*models.Bookmark, error) {
	var b models.Bookmark
	err := s.db.QueryRow(
