		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("get bookmark: %w", err)
	}
	return &b, nil
}

func (s *BookmarkStore) List() ([]models.Bookmark, error) {
	rows, err := s.db.Query("SELECT id, url, title, description, tags, created_at, updated_at FROM bookmarks ORDER BY created_at DESC")
