func (r *CreateBookmarkRequest) Validate() []ValidationError {
	var errs []ValidationError

	if r.URL == "" {
		errs = append(errs, ValidationError{"url", "URL is required"})
	} else {
		// Check URL format
		import_ok := len(r.URL) > 8 && (r.URL[:7] == "http://" || r.URL[:8] == "https://")
		if !import_ok {
			errs = append(errs, ValidationError{"url", "URL must start with http:// or https://"})
		}
	}

	if len(r.Title) > 200 {
		errs = append(errs, ValidationError{"title", "Title must be 200 characters or less"})
	}

	if len(r.Tags) > 10 {
		errs = append(errs, ValidationError{"tags", "Maximum 10 tags allowed"})
	}
	for i, tag := range r.Tags {
		if len(tag) > 50 {
			errs = append(errs, ValidationError{"tags", fmt.Sprintf("Tag %d exceeds 50 characters", i+1)})
		}
		if tag == "" {
			errs = append(errs, ValidationError{"tags", fmt.Sprintf("Tag %d is empty", i+1)})
		}
	}

	return errs
}"}}
