I'll add a WebSocket server that tracks connected users and send notifications in real-time. I'll integrate it with the notification service we already built so `createNotification` automatically pushes to connected clients.

```tool_call
{"name": "write_file", "arguments": {"path": "~/projects/collab-tool/src/lib/websocket.ts", "content": "import { WebSocketServer, WebSocket } from 'ws';
import { Server } from 'http';
import jwt from 'jsonwebtoken';

// Map of userId -> Set of connected WebSocket clients
const connections = new Map<string, Set<WebSocket>>();

export function setupWebSocket(server: Server) {
  const wss = new WebSocketServer({ server, path: '/ws' });

  wss.on('connection', (ws, req) => {
    // Authenticate via query parameter token
    const url = new URL(req.url || '', `http://${req.headers.host}`);
    const token = url.searchParams.get('token');

    if (!token) {
      ws.close(4001, 'Authentication required');
      return;
    }

    try {
      const payload = jwt.verify(token, process.env.JWT_SECRET || 'dev-secret') as { id: string };
      const userId = payload.id;

      // Track connection
      if (!connections.has(userId)) {
        connections.set(userId, new Set());
      }
      connections.get(userId)!.add(ws);

      ws.on('close', () => {
        connections.get(userId)?.delete(ws);
        if (connections.get(userId)?.size === 0) {
          connections.delete(userId);
        }
      });

      ws.send(JSON.stringify({ type: 'connected', userId }));
    } catch {
      ws.close(4001, 'Invalid token');
    }
  });

  return wss;
}

/**
 * Push a notification payload to a specific user's connected clients.
 * Called from the notification service when a new notification is created.
 */
export function pushToUser(userId: string, payload: any) {
  const userSockets = connections.get(userId);
  if (!userSockets) return;

  const message = JSON.stringify({ type: 'notification', data: payload });
  for (const ws of userSockets) {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(message);
    }
  }
}
"}}
