type ValidatorFn = (value: any, rule: ValidationRule, fieldName: string) => FieldError | null;

const validators: Record<string, ValidatorFn> = {
  required: (value, rule, field) => {
    if (value === undefined || value === null || value === '' || (Array.isArray(value) && value.length === 0)) {
      return { field, message: rule.message || `${field} is required` };
    }
    return null;
  },

  minLength: (value, rule, field) => {
    if (typeof value === 'string' && value.length < rule.value) {
      return { field, message: rule.message || `${field} must be at least ${rule.value} characters` };
    }
    return null;
  },

  maxLength: (value, rule, field) => {
    if (typeof value === 'string' && value.length > rule.value) {
      return { field, message: rule.message || `${field} must be at most ${rule.value} characters` };
    }
    return null;
  },

  pattern: (value, rule, field) => {
    if (typeof value === 'string' && !new RegExp(rule.value).test(value)) {
      return { field, message: rule.message || `${field} format is invalid` };
    }
    return null;
  },
};

export function validateField(fieldName: string, value: any, rules: ValidationRule[]): FieldError[] {
  const errors: FieldError[] = [];
  for (const rule of rules) {
    const validator = validators[rule.type];
    if (!validator) continue;
    const error = validator(value, rule, fieldName);
    if (error) errors.push(error);
  }
  return errors;
}

export function validateForm(values: Record<string, any>, schema: Record<string, ValidationRule[]>): FieldError[] {
  const errors: FieldError[] = [];
  for (const [field, rules] of Object.entries(schema)) {
    errors.push(...validateField(field, values[field], rules));
  }
  return errors;
}

export function registerValidator(name: string, fn: ValidatorFn): void {
  validators[name] = fn;
}
