{"name": "write_file", "arguments": {"path": "~/projects/form-lib/src/useForm.ts", "content": "import { useState, useCallback, FormEvent, ChangeEvent } from 'react';
import { ValidationRule, FieldError } from './types';
import { validateField, validateForm } from './validators';

interface UseFormConfig<T extends Record<string, any>> {
  initialValues: T;
  schema: Record<keyof T & string, ValidationRule[]>;
  onSubmit: (values: T) => void | Promise<void>;
  validateOnBlur?: boolean;
  validateOnChange?: boolean;
}

interface UseFormReturn<T extends Record<string, any>> {
  values: T;
  errors: Record<string, string[]>;
  touched: Record<string, boolean>;
  isSubmitting: boolean;
  isValid: boolean;
  handleChange: (e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => void;
  handleBlur: (e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => void;
  handleSubmit: (e: FormEvent) => void;
  setFieldValue: (field: keyof T & string, value: any) => void;
  setFieldError: (field: string, message: string) => void;
  resetForm: () => void;
}

export function useForm<T extends Record<string, any>>(config: UseFormConfig<T>): UseFormReturn<T> {
  const { initialValues, schema, onSubmit, validateOnBlur = true, validateOnChange = false } = config;

  const [values, setValues] = useState<T>({ ...initialValues });
  const [errors, setErrors] = useState<Record<string, string[]>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  const runFieldValidation = useCallback((field: string, value: any) => {
    const rules = schema[field as keyof T & string];
    if (!rules) return;
    const fieldErrors = validateField(field, value, rules);
    setErrors(prev => ({
      ...prev,
      [field]: fieldErrors.map(e => e.message),
    }));
  }, [schema]);

  const handleChange = useCallback((e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setValues(prev => ({ ...prev, [name]: value }));
    if (validateOnChange) {
      runFieldValidation(name, value);
    }
  }, [validateOnChange, runFieldValidation]);

  const handleBlur = useCallback((e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setTouched(prev => ({ ...prev, [name]: true }));
    if (validateOnBlur) {
      runFieldValidation(name, value);
    }
  }, [validateOnBlur, runFieldValidation]);

  const handleSubmit = useCallback(async (e: FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    // Mark all fields as touched
    const allTouched: Record<string, boolean> = {};
    for (const key of Object.keys(schema)) {
      allTouched[key] = true;
    }
    setTouched(allTouched);

    // Run full validation using validateForm from our validators module
    const allErrors = validateForm(values, schema as Record<string, ValidationRule[]>);
    const errorMap: Record<string, string[]> = {};
    for (const err of allErrors) {
      if (!errorMap[err.field]) errorMap[err.field] = [];
      errorMap[err.field].push(err.message);
    }
    setErrors(errorMap);

    if (allErrors.length === 0) {
      await onSubmit(values);
    }
    setIsSubmitting(false);
  }, [values, schema, onSubmit]);

  const setFieldValue = useCallback((field: keyof T & string, value: any) => {
    setValues(prev => ({ ...prev, [field]: value }));
  }, []);

  const setFieldError = useCallback((field: string, message: string) => {
    setErrors(prev => ({ ...prev, [field]: [message] }));
  }, []);

  const resetForm = useCallback(() => {
    setValues({ ...initialValues });
    setErrors({});
    setTouched({});
    setIsSubmitting(false);
  }, [initialValues]);

  const isValid = Object.values(errors).every(fieldErrors => fieldErrors.length === 0);

  return {
    values,
    errors,
    touched,
    isSubmitting,
    isValid,
    handleChange,
    handleBlur,
    handleSubmit,
    setFieldValue,
    setFieldError,
    resetForm,
  };
}
"}}
