	// Ensure migrations tracking table exists
	if err := ensureMigrationsTable(db); err != nil {
		log.Fatal(err)
	}

	switch os.Args[1] {
	case "up":
		if err := migrateUp(db, "migrations"); err != nil {
			log.Fatal(err)
		}
	case "status":
		if err := showStatus(db, "migrations"); err != nil {
			log.Fatal(err)
		}
	default:
		fmt.Printf("Unknown command: %s\n", os.Args[1])
		os.Exit(1)
	}
}

func ensureMigrationsTable(db *sql.DB) error {
	_, err := db.Exec(`
		CREATE TABLE IF NOT EXISTS schema_migrations (
			version VARCHAR(255) PRIMARY KEY,
			applied_at TIMESTAMP DEFAULT NOW()
		)
	`)
	return err
}

func getAppliedMigrations(db *sql.DB) (map[string]bool, error) {
	rows, err := db.Query("SELECT version FROM schema_migrations ORDER BY version")
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	applied := make(map[string]bool)
	for rows.Next() {
		var version string
		if err := rows.Scan(&version); err != nil {
			return nil, err
		}
		applied[version] = true
	}
	return applied, nil
}

func findMigrationFiles(dir string, suffix string) ([]string, error) {
	pattern := filepath.Join(dir, fmt.Sprintf("*%s", suffix))
	files, err := filepath.Glob(pattern)
	if err != nil {
		return nil, err
	}
	sort.Strings(files)
	return files, nil
}

func versionFromFile(filename string) string {
	base := filepath.Base(filename)
	// 001_create_users.up.sql -> 001_create_users
	base = strings.TrimSuffix(base, ".up.sql")
	base = strings.TrimSuffix(base, ".down.sql")
	return base
}

func migrateUp(db *sql.DB, dir string) error {
	applied, err := getAppliedMigrations(db)
	if err != nil {
		return err
	}

	files, err := findMigrationFiles(dir, ".up.sql")
	if err != nil {
		return err
	}

	count := 0
	for _, file := range files {
		version := versionFromFile(file)
		if applied[version] {
			continue
		}

		sqlBytes, err := os.ReadFile(file)
		if err != nil {
			return fmt.Errorf("reading %s: %w", file, err)
		}

		// Run migration in a transaction
		tx, err := db.Begin()
		if err != nil {
			return err
		}

		if _, err := tx.Exec(string(sqlBytes)); err != nil {
			tx.Rollback()
			return fmt.Errorf("applying %s: %w", version, err)
		}

		if _, err := tx.Exec("INSERT INTO schema_migrations (version) VALUES ($1)", version); err != nil {
			tx.Rollback()
			return fmt.Errorf("recording %s: %w", version, err)
		}

		if err := tx.Commit(); err != nil {
			return err
		}

		fmt.Printf("  Applied: %s\n", version)
		count++
	}

	if count == 0 {
		fmt.Println("No new migrations to apply.")
	} else {
		fmt.Printf("\nApplied %d migration(s).\n", count)
	}
	return nil
}

func showStatus(db *sql.DB, dir string) error {
	applied, err := getAppliedMigrations(db)
	if err != nil {
		return err
