import { logger } from './logger';
import { config } from './config';

interface RequestOptions {
  method: 'GET' | 'POST' | 'PUT' | 'DELETE';
  url: string;
  headers?: Record<string, string>;
  body?: unknown;
  timeout?: number;
}

interface RequestResult<T> {
  data: T;
  status: number;
  headers: Record<string, string>;
}

export async function request<T>(options: RequestOptions): Promise<RequestResult<T>> {
  const timeout = options.timeout ?? config.get('http.timeout', 30000);
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeout);

  try {
    logger.debug(`${options.method} ${options.url}`);
    const response = await fetch(options.url, {
      method: options.method,
      headers: {
        'Content-Type': 'application/json',
        ...options.headers,
      },
      body: options.body ? JSON.stringify(options.body) : undefined,
      signal: controller.signal,
    });

    const data = await response.json() as T;
    return { data, status: response.status, headers: Object.fromEntries(response.headers) };
  } finally {
    clearTimeout(timer);
  }
}

