import { config } from './config';

interface RetryOptions {
  maxRetries?: number;
  baseDelay?: number;
  maxDelay?: number;
  backoffMultiplier?: number;
  retryOn?: (error: unknown) => boolean;
}

interface RetryResult<T> {
  data: T;
  attempts: number;
}

export async function retry<T>(
  fn: () => Promise<T>,
  options?: RetryOptions
): Promise<RetryResult<T>> {
  const maxRetries = options?.maxRetries ?? config.get('retry.maxRetries', 3);
  const baseDelay = options?.baseDelay ?? config.get('retry.baseDelay', 1000);
  const maxDelay = options?.maxDelay ?? config.get('retry.maxDelay', 30000);
  const multiplier = options?.backoffMultiplier ?? 2;
  const shouldRetry = options?.retryOn ?? (() => true);

  let lastError: unknown;

  for (let attempt = 1; attempt <= maxRetries + 1; attempt++) {
    try {
      const data = await fn();
      if (attempt > 1) {
        logger.info(`Retry succeeded on attempt ${attempt}`);
      }
      return { data, attempts: attempt };
    } catch (error) {
      lastError = error;

      if (attempt > maxRetries || !shouldRetry(error)) {
        logger.error(`All ${attempt} attempt(s) failed`);
        throw error;
      }

      const delay = Math.min(baseDelay * multiplier ** (attempt - 1), maxDelay);
      const jitter = delay * (0.5 + Math.random() * 0.5);
      logger.warn(`Attempt ${attempt} failed, retrying in ${Math.round(jitter)}ms`);
      await sleep(jitter);
    }
  }

  throw lastError;
}

function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}
