export async function extract(source: DataSource): Promise<RawRecord[]> {
  logger.info(`Extracting from ${source.name}`);

  const result = await request<{ records: RawRecord[] }>({
    method: 'GET',
    url: source.url,
    headers: source.headers,
    timeout: config.get('extract.timeout', 60000),
  });

  if (result.status !== 200) {
    throw new Error(`Extraction failed with status ${result.status}`);
  }

  logger.info(`Extracted ${result.data.records.length} records from ${source.name}`);
  return result.data.records;
}

