The problem is clear: handlers duplicate error handling, and the `AppError` type isn't being used effectively. I'll create an error recovery middleware that:
- Catches panics (converts to 500)
- Uses `AppError` for consistent responses
- Matches the existing `func(http.Handler) http.Handler` middleware signature

But first, the handlers need a way to return `AppError` instead of writing responses manually. I'll create a handler wrapper type that matches this pattern.

```tool_call
{"name": "write_file", "arguments": {"path": "~/projects/payment-api/internal/middleware/recovery.go", "content": "package middleware

import (
	"errors"
	"log"
	"net/http"
	"runtime/debug"

	"github.com/acme/payment-api/internal/models"
	"github.com/acme/payment-api/pkg/response"
)

// HandlerFunc is a handler that returns an error instead of writing it directly.
// This enables consistent error handling through the middleware.
type HandlerFunc func(w http.ResponseWriter, r *http.Request) error

// WrapHandler converts our error-returning HandlerFunc into a standard http.HandlerFunc.
// If the handler returns an *AppError, it's rendered with the correct status code and message.
// If it returns a generic error, it's treated as a 500.
func WrapHandler(fn HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if err := fn(w, r); err != nil {
			var appErr *models.AppError
			if errors.As(err, &appErr) {
				response.JSON(w, appErr.Code, map[string]interface{}{
					"error": appErr.Message,
					"detail": appErr.Detail,
				})
			} else {
				log.Printf("Unhandled error: %v", err)
				response.JSON(w, http.StatusInternalServerError, map[string]interface{}{
					"error": "Internal server error",
				})
			}
		}
	}
}

// Recovery catches panics and converts them to 500 responses.
// Follows the same func(http.Handler) http.Handler pattern as Logging middleware.
func Recovery(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		defer func() {
			if rec := recover(); rec != nil {
				log.Printf("PANIC: %v\n%s", rec, debug.Stack())
				response.JSON(w, http.StatusInternalServerError, map[string]interface{}{
					"error": "Internal server error",
				})
			}
		}()
		next.ServeHTTP(w, r)
	})
}
"}}
