use axum::http::StatusCode;
use axum::response::{IntoResponse, Response};
use axum::Json;
use serde_json::json;

#[derive(Debug)]
pub enum AppError {
    NotFound,
    BadRequest(String),
    Internal(String),
}

impl IntoResponse for AppError {
    fn into_response(self) -> Response {
        let (status, message) = match self {
            AppError::NotFound => (StatusCode::NOT_FOUND, "Resource not found".to_string()),
            AppError::BadRequest(msg) => (StatusCode::BAD_REQUEST, msg),
            AppError::Internal(msg) => (StatusCode::INTERNAL_SERVER_ERROR, msg),
        };
        (status, Json(json!({"error": message}))).into_response()
    }
}

impl From<sqlx::Error> for AppError {
    fn from(err: sqlx::Error) -> Self {
        AppError::Internal(err.to_string())
    }
}

Now I have the full picture. The conventions are:

1. **Separation**: routes define paths, handlers contain logic
2. **`Router<AppState>`**: all route functions return `Router<AppState>`
3. **Handler signatures**: `State(state): State<AppState>`, return `Result<Json<T>, AppError>`
4. **Error handling**: `AppError` enum with `IntoResponse`
5. **Database**: `sqlx` with `PgPool` via `AppState`
6. **Module pattern**: `mod.rs` re-exports and `create_router` merges all routes

